class Solution(object):
    def sumOfLargestPrimes(self, s):
        def is_prime(n):
            if n < 2:
                return False
            if n < 4:
                return True
            if n % 2 == 0 or n % 3 == 0:
                return False
            i = 5
            while i * i <= n:
                if n % i == 0 or n % (i + 2) == 0:
                    return False
                i += 6
            return True

        primes = set()
        n = len(s)
        for i in range(n):
            for j in range(i + 1, n + 1):
                num = int(s[i:j])
                if is_prime(num):
                    primes.add(num)

        top3 = sorted(primes, reverse=True)[:3]
        return sum(top3)
